import{_ as e,o as r,c as a,ak as o}from"./chunks/framework.DwHlt8HN.js";const f=JSON.parse('{"title":"Introduction","description":"XW37-BLE low-power Bluetooth 5.2 module introduction","frontmatter":{"title":"Introduction","description":"XW37-BLE low-power Bluetooth 5.2 module introduction"},"headers":[],"relativePath":"docs/overview/introduction.md","filePath":"docs/overview/introduction.md"}'),n={name:"docs/overview/introduction.md"};function i(l,t,s,d,c,h){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="xw37-ble-5-2-module" tabindex="-1">XW37-BLE 5.2 Module <a class="header-anchor" href="#xw37-ble-5-2-module" aria-label="Permalink to “XW37-BLE 5.2 Module”">​</a></h1><p><strong>Version:</strong> V1.0<br><strong>Date:</strong> 2023.12.13<br><strong>Manufacturer:</strong> XW-CHIP TECHNOLOGY</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to “Overview”">​</a></h2><p>The <strong>XW37-BLE</strong> is a low-power Bluetooth 5.2 module. It integrates a high-performance 2.4GHz RF transceiver, a feature-rich baseband processor, a 32-bit MCU running at 32 MHz, and various peripheral interfaces.</p><h2 id="key-specifications" tabindex="-1">Key Specifications <a class="header-anchor" href="#key-specifications" aria-label="Permalink to “Key Specifications”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Specification</th><th style="text-align:left;">Value</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Bluetooth Version</strong></td><td style="text-align:left;">5.2</td></tr><tr><td style="text-align:left;"><strong>MCU</strong></td><td style="text-align:left;">32-bit @ 32 MHz</td></tr><tr><td style="text-align:left;"><strong>Flash</strong></td><td style="text-align:left;">2 Mbit SiP</td></tr><tr><td style="text-align:left;"><strong>RAM</strong></td><td style="text-align:left;">32 KB</td></tr><tr><td style="text-align:left;"><strong>ROM</strong></td><td style="text-align:left;">32 KB</td></tr><tr><td style="text-align:left;"><strong>Communication Distance</strong></td><td style="text-align:left;">Up to 40m (open area @ 0dBm)</td></tr><tr><td style="text-align:left;"><strong>Max Packet Size</strong></td><td style="text-align:left;">20 bytes/frame</td></tr><tr><td style="text-align:left;"><strong>Power Supply</strong></td><td style="text-align:left;">1.7V - 3.3V (3.0V recommended)</td></tr><tr><td style="text-align:left;"><strong>Dimensions</strong></td><td style="text-align:left;">18mm × 12mm × 1.7mm</td></tr></tbody></table><h2 id="disclaimer" tabindex="-1">Disclaimer <a class="header-anchor" href="#disclaimer" aria-label="Permalink to “Disclaimer”">​</a></h2><p>All information in this document is provided based on the current product status and is subject to change without notice. This document carries no warranty of any kind.</p><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>The content may change due to product upgrades; users should contact the company for the latest information.</p></div><h2 id="version-history" tabindex="-1">Version History <a class="header-anchor" href="#version-history" aria-label="Permalink to “Version History”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Version</th><th style="text-align:left;">Date</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>V1.0</strong></td><td style="text-align:left;">2023.12.13</td><td style="text-align:left;">Initial version by Jerk</td></tr></tbody></table><h2 id="contact-information" tabindex="-1">Contact Information <a class="header-anchor" href="#contact-information" aria-label="Permalink to “Contact Information”">​</a></h2><ul><li><strong>Website:</strong> <a href="http://www.xw-chip.com" target="_blank" rel="noreferrer">www.xw-chip.com</a></li><li><strong>Phone:</strong> 86-755-27784247</li><li><strong>Address:</strong> Room 603, Chungu, Bldg 2, Meisheng Huigu Science Park, Bao&#39;an District, Shenzhen, China</li></ul>',13)])])}const m=e(n,[["render",i]]);export{f as __pageData,m as default};
